        {
            _currentWarehouseId = warehouseId;
            LowStockCount = 0;
            OnChange?.Invoke();
        }
    }

    public void UpdateLowStockCount(int count)
    {
        LowStockCount = count;
        OnChange?.Invoke();
    }

    public record WarehouseInfo(string Id, string Name);
}

