@using sv_34954468483c4c38ad69b2ed9b383c45.Services
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4 fw-semibold">@State.CurrentWarehouseName</p>
                <p class="card-text text-muted">ID: @State.CurrentWarehouseId</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(State.LowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body">
                <h5 class="card-title">Low Stock Alerts</h5>
                @if (State.LowStockCount > 0)
                {
                    <p class="card-text fs-1 fw-bold text-danger">@State.LowStockCount</p>
                    <p class="card-text text-muted">items below minimum level</p>
                }
                else
                {
                    <p class="card-text fs-1 fw-bold text-success">0</p>
                    <p class="card-text text-muted">all stock levels healthy</p>
                }
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text">
                    <span class="badge bg-success">● Live</span>
                    <span class="text-muted ms-2">every 10s</span>
                </p>
                @if (_lastChecked.HasValue)
                {
                    <p class="card-text text-muted small">Last checked: @_lastChecked.Value.ToString("HH:mm:ss")</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter] public WarehouseState State { get; set; } = default!;

    private Timer? _pollingTimer;
    private DateTime? _lastChecked;

    protected override void OnInitialized()
    {
        State.OnChange += HandleStateChange;
        StartPolling();
    }

    private void StartPolling()
    {
        // Poll immediately, then every 10 seconds
        _pollingTimer = new Timer(async _ => await PollAlerts(), null, TimeSpan.Zero, TimeSpan.FromSeconds(10));
    }

    private async Task PollAlerts()
    {
        try
        {
            var count = await AlertService.GetLowStockCountAsync(State.CurrentWarehouseId);
            _lastChecked = DateTime.Now;
            State.UpdateLowStockCount(count);
        }
        catch
        {
            // Swallow errors during polling; the timer will retry
        }
    }

    private void HandleStateChange()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        State.OnChange -= HandleStateChange;
        _pollingTimer?.Dispose();
    }
}

